'use strict';

// MODULES //

var isNumber = require( '@stdlib/assert/is-number' ).isPrimitive;
var isBoolean = require( '@stdlib/assert/is-boolean' ).isPrimitive;
var isComplexLike = require( '@stdlib/assert/is-complex-like' );
var complexDataType = require( '@stdlib/complex/dtype' );
var defaults = require( '@stdlib/ndarray/defaults' );


// VARIABLES //

var DEFAULT_REAL = defaults.get( 'dtypes.real_floating_point' );
var DEFAULT_CMPLX = defaults.get( 'dtypes.complex_floating_point' );
var DEFAULT_BOOL = defaults.get( 'dtypes.boolean' );


// MAIN //

/**
* Resolves a default ndarray data type from a scalar value.
*
* ## Notes
*
* -   If `value` is a number, the returned data type is the default real-valued floating-point data type.
* -   If `value` is a boolean, the returned data type is the default boolean data type.
* -   If `value` is a complex number object of a known complex data type, the returned data type is the corresponding complex data type.
* -   If `value` is a complex number object of an unknown complex data type, the returned data type is the default complex-valued floating-point data type.
* -   For any other value, the returned data type is `'generic'`.
*
* @param {*} value - scalar value
* @returns {string} ndarray data type
*
* @example
* var dt = scalarDataType( 3.14 );
* // returns <string>
*
* @example
* var dt = scalarDataType( true );
* // returns <string>
*
* @example
* var dt = scalarDataType( 'beep' );
* // returns 'generic'
*/
function scalarDataType( value ) {
	var dt;
	if ( isNumber( value ) ) {
		return DEFAULT_REAL;
	}
	if ( isBoolean( value ) ) {
		return DEFAULT_BOOL;
	}
	if ( isComplexLike( value ) ) {
		dt = complexDataType( value );
		if ( dt === null ) {
			return DEFAULT_CMPLX;
		}
		return dt;
	}
	return 'generic';
}


// EXPORTS //

module.exports = scalarDataType;
